+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Events (ID 30168).
+/// Handles clearing Shopify-specific fields when copying sales documents.
+/// </summary>
+codeunit 30168 "Shpfy Copy Document Events"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesHeader', '', false, false)]
+    local procedure OnAfterCopySalesHeaderClearShopifyFields(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesHeader: Record "Sales Header"; FromDocType: Enum "Sales Document Type From")
+    begin
+        ClearShopifyOrderFields(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesDocOnAfterTransferPostedInvoiceFields', '', false, false)]
+    local procedure OnCopySalesDocOnAfterTransferPostedInvoiceFieldsClearShopifyFields(var ToSalesHeader: Record "Sales Header"; SalesInvoiceHeader: Record "Sales Invoice Header"; OldSalesHeader: Record "Sales Header")
+    begin
+        ClearShopifyOrderFields(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyPostedShipment', '', false, false)]
+    local procedure OnAfterCopyPostedShipmentClearShopifyFields(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesShipmentHeader: Record "Sales Shipment Header")
+    begin
+        ClearShopifyOrderFields(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyPostedReturnReceipt', '', false, false)]
+    local procedure OnAfterCopyPostedReturnReceiptClearShopifyFields(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; ReturnReceiptHeader: Record "Return Receipt Header")
+    begin
+        ClearShopifyOrderFields(ToSalesHeader);
+    end;
+
+    local procedure ClearShopifyOrderFields(var SalesHeader: Record "Sales Header")
+    begin
+        SalesHeader."Shpfy Order Id" := 0;
+        SalesHeader."Shpfy Order No." := '';
+    end;
+}

